import React, { memo, useEffect } from 'react'
import type { FC, ReactNode } from 'react'
import { createRef } from 'react'
import { createPluginUI } from 'molstar/lib/mol-plugin-ui'
import { PluginUIContext } from 'molstar/lib/mol-plugin-ui/context'
import PanelMenu from '../../c-cpns/panel-menu'
import PanelBody from '../../c-cpns/panel-body'
import { Protein3DStructureWrapper } from './style'
import { DefaultPluginUISpec } from 'molstar/lib/mol-plugin-ui/spec'
import { PluginCommands } from 'molstar/lib/mol-plugin/commands'
import { ColorNames } from 'molstar/lib/mol-util/color/names'
// import { Structure } from '../mol-model/structure'
/*  Might require extra configuration,
see https://webpack.js.org/loaders/sass-loader/ for example.
create-react-app should support this natively. */
// import 'molstar/lib/mol-plugin-ui/skin/light.scss'
import 'molstar/build/viewer/molstar.css'

interface Iprops {
  children?: ReactNode
}

declare global {
  interface Window {
    molstar?: PluginUIContext
  }
}

let p3dMolstar

const Protein3DStructure: FC<Iprops> = () => {
  const parent = createRef<HTMLDivElement>()

  useEffect(() => {
    async function init() {
      p3dMolstar = await createPluginUI(parent.current as HTMLDivElement, {
        ...DefaultPluginUISpec(),
        layout: {
          initial: {
            isExpanded: false,
            showControls: false
          }
        },
        components: {
          remoteState: 'none'
        }
      })

      const renderer = p3dMolstar.canvas3d!.props.renderer
      PluginCommands.Canvas3D.SetSettings(p3dMolstar, {
        settings: { renderer: { ...renderer, backgroundColor: ColorNames.white } }
      })

      const data = await p3dMolstar.builders.data.download(
        { url: 'https://alphafold.ebi.ac.uk/files/AF-W0GGK0-F1-model_v4.pdb' },
        { state: { isGhost: false } }
      )
      const trajectory = await p3dMolstar.builders.structure.parseTrajectory(data, 'pdb')
      await p3dMolstar.builders.structure.hierarchy.applyPreset(trajectory, 'default')
    }

    init()
    return () => {
      p3dMolstar?.dispose()
      p3dMolstar = undefined
    }
  }, [])

  return (
    <Protein3DStructureWrapper id='protein3dstructure'>
      <PanelMenu to='/protein3dstructure' name='Protein 3D Structure' did='rna3dstructure' />
      <PanelBody>
        <div id='rna-3d-structure111'>
          <div ref={parent} style={{ width: 640, height: 480 }} />
        </div>
      </PanelBody>
    </Protein3DStructureWrapper>
  )
}

export default memo(Protein3DStructure)
